def factorial(n):
    # Base case: factorial of 0 or 1 is 1 — no more recursion needed
    if n <= 1:
        return 1  # Smallest version — answer is known immediately
    # Recursive case: n! = n * (n-1)! — call factorial with smaller n
    return n * factorial(n - 1)
    # For n=4: return 4 * factorial(3)
    #   factorial(3) = 3 * factorial(2)
    #     factorial(2) = 2 * factorial(1)
    #       factorial(1) = 1 (base case!) -> unwinds: 2*1, 3*2, 4*6 = 24

def fibonacci(n):
    # Base cases: first two numbers in the sequence are 0 and 1
    if n <= 0:
        return 0
    if n == 1:
        return 1
    # Recursive case: fib(n) = fib(n-1) + fib(n-2)
    return fibonacci(n - 1) + fibonacci(n - 2)

print("Factorial of 5:", factorial(5))
print("Fibonacci of 7:", fibonacci(7))
# Expected output:
# Factorial of 5: 120
# Fibonacci of 7: 13
